body.script:
/* ══════════════════════════════════════════
   1. CUSTOM CURSOR
══════════════════════════════════════════ */
(function initCursor() {
  const cursor = document.getElementById('cursor');
  const ring   = document.getElementById('cursorRing');
  if (!cursor || !ring) return;
  let mx = 0, my = 0, rx = 0, ry = 0;
  document.addEventListener('mousemove', e => { mx = e.clientX; my = e.clientY; });
  (function animCursor() {
    rx += (mx - rx) * 0.18;
    ry += (my - ry) * 0.18;
    cursor.style.left = mx + 'px'; cursor.style.top = my + 'px';
    ring.style.left   = rx + 'px'; ring.style.top  = ry + 'px';
    requestAnimationFrame(animCursor);
  })();
  document.querySelectorAll('a, button').forEach(el => {
    el.addEventListener('mouseenter', () => {
      cursor.style.width = '20px'; cursor.style.height = '20px';
      ring.style.width   = '52px'; ring.style.height  = '52px';
    });
    el.addEventListener('mouseleave', () => {
      cursor.style.width = '12px'; cursor.style.height = '12px';
      ring.style.width   = '36px'; ring.style.height  = '36px';
    });
  });
})();

/* ══════════════════════════════════════════
   2. NAVBAR SCROLL STATE
══════════════════════════════════════════ */
(function initNavbar() {
  const navbar = document.getElementById('navbar');
  if (!navbar) return;
  window.addEventListener('scroll', () => {
    navbar.classList.toggle('scrolled', window.scrollY > 40);
  });
})();

/* ══════════════════════════════════════════
   3. HERO PARALLAX
══════════════════════════════════════════ */
(function initHeroParallax() {
  const layers = document.querySelectorAll('.parallax-layer[data-depth]');
  if (!layers.length) return;
  document.addEventListener('mousemove', e => {
    const cx = window.innerWidth  / 2;
    const cy = window.innerHeight / 2;
    const dx = (e.clientX - cx) / cx;
    const dy = (e.clientY - cy) / cy;
    layers.forEach(layer => {
      const d = parseFloat(layer.dataset.depth);
      layer.style.transform = `translate(${dx * d * 30}px, ${dy * d * 30}px)`;
    });
  });
  window.addEventListener('scroll', () => {
    const sy = window.scrollY;
    layers.forEach(layer => {
      const d = parseFloat(layer.dataset.depth);
      layer.style.transform = `translateY(${-sy * d * 0.5}px)`;
    });
  });
})();

/* ══════════════════════════════════════════
   4. HAMBURGER MENU
══════════════════════════════════════════ */
(function initHamburger() {
  const btn = document.getElementById('hamburger');
  const nl  = document.getElementById('navLinks');
  if (!btn || !nl) return;
  btn.addEventListener('click', () => {
    nl.classList.toggle('open');
  });
})();

/* ══════════════════════════════════════════
   5. HYPERSPEED ROAD CANVAS
══════════════════════════════════════════ */
(function initHyperspeed() {
  const container = document.getElementById('lights');
  if (!container) return;

  const canvas = document.createElement('canvas');
  container.appendChild(canvas);
  const ctx = canvas.getContext('2d');

  const CFG = {
    roadWidth:   0.45,
    islandWidth: 0.04,
    laneCount:   4,
    lightCount:  48,
    stickCount:  22,
    stickColor:  '#03b3c3',
    leftColors:  ['#d856bf', '#6750a2', '#c247ac'],
    rightColors: ['#03b3c3', '#0e5ea5', '#324555'],
    fogColor:    [10, 15, 28],
    baseSpeed:   0.012,
    boostSpeed:  0.032,
    trailAlpha:  0.18,
  };

  let W = 0, H = 0, cx = 0;
  let speed = CFG.baseSpeed, targetSpd = CFG.baseSpeed;
  let timeOff = 0, lastTime = performance.now();

  function resize() {
    W = canvas.width  = container.offsetWidth  || window.innerWidth;
    H = canvas.height = container.offsetHeight || window.innerHeight;
    cx = W / 2;
  }
  resize();
  window.addEventListener('resize', resize);

  const rnd  = (a, b) => Math.random() * (b - a) + a;
  const pick = arr => arr[Math.floor(Math.random() * arr.length)];

  function vp() { return { x: cx, y: H * 0.40 }; }

  function project(roadX, z) {
    const v = vp();
    const hw = W * CFG.roadWidth / 2 * (1 - z);
    const sx = v.x + roadX * hw;
    const sy = v.y + (H - v.y) * (1 - z);
    return { x: sx, y: sy };
  }

  function makeCar(side) {
    const laneCount = CFG.laneCount;
    const lane      = Math.floor(Math.random() * laneCount);
    const laneX     = ((lane + 0.5) / laneCount * 2 - 1);
    const halfRoad  = 0.5;
    const sign      = side === 'left' ? -1 : 1;
    const roadX     = sign * halfRoad * (0.1 + Math.abs(laneX) * 0.9);
    const spread    = (Math.random() - 0.5) * 0.18;
    return {
      roadX: roadX + spread,
      z: Math.random(),
      color: pick(side === 'left' ? CFG.leftColors : CFG.rightColors),
      speed: rnd(0.3, 0.7),
      length: rnd(0.06, 0.20),
      width: rnd(0.003, 0.008),
      side,
    };
  }

  const cars = [];
  for (let i = 0; i < CFG.lightCount; i++) {
    cars.push(makeCar('left'));
    cars.push(makeCar('right'));
  }

  function makeStick(side) {
    return { side, z: Math.random(), speed: rnd(0.4, 0.8), height: rnd(0.025, 0.055), width: rnd(0.004, 0.010) };
  }
  const sticks = [];
  for (let i = 0; i < CFG.stickCount; i++) {
    sticks.push(makeStick('left'));
    sticks.push(makeStick('right'));
  }

  function drawRoad() {
    const v  = vp();
    const hw = W * CFG.roadWidth / 2;
    const iw = W * CFG.islandWidth / 2;

    ctx.beginPath();
    ctx.moveTo(v.x - iw * 0.1, v.y);
    ctx.lineTo(v.x + iw * 0.1, v.y);
    ctx.lineTo(v.x + hw, H);
    ctx.lineTo(v.x - hw, H);
    ctx.closePath();
    const rg = ctx.createLinearGradient(0, v.y, 0, H);
    rg.addColorStop(0,   'rgba(8,8,8,0)');
    rg.addColorStop(0.3, 'rgba(8,8,8,0.8)');
    rg.addColorStop(1,   'rgba(8,8,8,1)');
    ctx.fillStyle = rg;
    ctx.fill();

    ctx.strokeStyle = 'rgba(255,255,255,0.35)';
    ctx.lineWidth = 1.5;
    ctx.beginPath();
    ctx.moveTo(v.x - hw, H); ctx.lineTo(v.x - iw * 0.1, v.y);
    ctx.stroke();
    ctx.beginPath();
    ctx.moveTo(v.x + hw, H); ctx.lineTo(v.x + iw * 0.1, v.y);
    ctx.stroke();

    const lanes = CFG.laneCount;
    ctx.setLineDash([H * 0.04, H * 0.06]);
    ctx.strokeStyle = 'rgba(255,255,255,0.18)';
    ctx.lineWidth = 1;
    for (let l = 1; l < lanes; l++) {
      const frac = l / lanes;
      const lxF = v.x - iw * 0.1 - (hw - iw * 0.1) * frac;
      const lxN = v.x - hw + (hw - iw * 0.1) * (1 - frac);
      ctx.beginPath();
      ctx.moveTo(lxF, v.y); ctx.lineTo(lxN, H);
      ctx.stroke();
      const rxF = v.x + iw * 0.1 + (hw - iw * 0.1) * frac;
      const rxN = v.x + hw - (hw - iw * 0.1) * (1 - frac);
      ctx.beginPath();
      ctx.moveTo(rxF, v.y); ctx.lineTo(rxN, H);
      ctx.stroke();
    }
    ctx.setLineDash([]);

    ctx.beginPath();
    ctx.moveTo(v.x - iw * 0.1, v.y);
    ctx.lineTo(v.x + iw * 0.1, v.y);
    ctx.lineTo(v.x + iw, H);
    ctx.lineTo(v.x - iw, H);
    ctx.closePath();
    ctx.fillStyle = 'rgba(10,10,10,0.9)';
    ctx.fill();
  }

  function hexToRgba(hex, alpha) {
    const r = parseInt(hex.slice(1,3), 16);
    const g = parseInt(hex.slice(3,5), 16);
    const b = parseInt(hex.slice(5,7), 16);
    return `rgba(${r},${g},${b},${alpha.toFixed(3)})`;
  }

  function drawCar(car) {
    const zNear = car.z;
    const zFar  = Math.min(1, car.z + car.length);
    if (zNear >= 1) return;
    const pNear = project(car.roadX, zNear);
    const pFar  = project(car.roadX, zFar);
    const wNear = Math.max(1, W * car.width * (1 - zNear));
    const wFar  = Math.max(0.5, W * car.width * (1 - zFar));
    const dx = pFar.x - pNear.x, dy = pFar.y - pNear.y;
    const len = Math.sqrt(dx * dx + dy * dy) || 1;
    const nx = dy / len, ny = -dx / len;
    ctx.beginPath();
    ctx.moveTo(pNear.x - nx * wNear, pNear.y - ny * wNear);
    ctx.lineTo(pFar.x  - nx * wFar,  pFar.y  - ny * wFar);
    ctx.lineTo(pFar.x  + nx * wFar,  pFar.y  + ny * wFar);
    ctx.lineTo(pNear.x + nx * wNear, pNear.y + ny * wNear);
    ctx.closePath();
    const alpha = Math.pow(1 - zNear, 1.5) * 0.9;
    const g = ctx.createLinearGradient(pFar.x, pFar.y, pNear.x, pNear.y);
    g.addColorStop(0,   hexToRgba(car.color, 0));
    g.addColorStop(0.4, hexToRgba(car.color, alpha * 0.5));
    g.addColorStop(1,   hexToRgba(car.color, alpha));
    ctx.fillStyle = g;
    ctx.fill();
    if (zNear < 0.85) {
      ctx.beginPath();
      ctx.arc(pNear.x, pNear.y, wNear * 0.8, 0, Math.PI * 2);
      ctx.fillStyle = hexToRgba(car.color, Math.min(1, alpha * 1.4));
      ctx.fill();
    }
  }

  function drawStick(stick) {
    if (stick.z >= 1) return;
    const sign = stick.side === 'left' ? -1 : 1;
    const roadEdge = sign * 0.5;
    const p = project(roadEdge, stick.z);
    const h = H * stick.height * (1 - stick.z) * 0.5;
    const w = Math.max(1, W * stick.width * (1 - stick.z));
    const alpha = Math.pow(1 - stick.z, 1.2) * 0.85;
    const g = ctx.createLinearGradient(p.x, p.y - h, p.x, p.y);
    g.addColorStop(0,   hexToRgba(CFG.stickColor, 0));
    g.addColorStop(0.4, hexToRgba(CFG.stickColor, alpha));
    g.addColorStop(1,   hexToRgba(CFG.stickColor, alpha * 0.6));
    ctx.fillStyle = g;
    ctx.fillRect(p.x - w / 2, p.y - h, w, h);
    ctx.shadowColor = CFG.stickColor;
    ctx.shadowBlur  = 8 * (1 - stick.z);
    ctx.fillStyle   = hexToRgba(CFG.stickColor, alpha);
    ctx.fillRect(p.x - w / 2, p.y - h * 0.15, w, h * 0.15);
    ctx.shadowBlur  = 0;
  }

  function draw(now) {
    const dt = Math.min((now - lastTime) / 1000, 0.05);
    lastTime = now;
    speed += (targetSpd - speed) * 0.06;
    timeOff += speed;

    const [fr, fg, fb] = CFG.fogColor;
    ctx.fillStyle = `rgba(${fr},${fg},${fb},${CFG.trailAlpha})`;
    ctx.fillRect(0, 0, W, H);

    drawRoad();

    sticks.sort((a, b) => b.z - a.z);
    for (const stick of sticks) {
      drawStick(stick);
      stick.z -= speed * stick.speed;
      if (stick.z <= 0) {
        stick.z = 1;
        stick.speed  = rnd(0.4, 0.8);
        stick.height = rnd(0.025, 0.055);
        stick.width  = rnd(0.004, 0.010);
      }
    }

    cars.sort((a, b) => b.z - a.z);
    for (const car of cars) {
      drawCar(car);
      car.z -= speed * car.speed;
      if (car.z <= 0) {
        const side  = car.side;
        const fresh = makeCar(side);
        fresh.z = 0.95 + Math.random() * 0.05;
        Object.assign(car, fresh);
      }
    }

    requestAnimationFrame(draw);
  }

  container.addEventListener('mousedown',   () => { targetSpd = CFG.boostSpeed; });
  container.addEventListener('mouseup',     () => { targetSpd = CFG.baseSpeed; });
  container.addEventListener('mouseleave',  () => { targetSpd = CFG.baseSpeed; });
  container.addEventListener('touchstart',  () => { targetSpd = CFG.boostSpeed; }, { passive: true });
  container.addEventListener('touchend',    () => { targetSpd = CFG.baseSpeed; },  { passive: true });

  requestAnimationFrame(draw);
})();

/* ══════════════════════════════════════════
   6. SCROLL REVEAL
══════════════════════════════════════════ */
(function initScrollReveal() {
  const els = document.querySelectorAll('.js-reveal');
  if (!els.length) return;
  const obs = new IntersectionObserver(entries => {
    entries.forEach(e => {
      if (e.isIntersecting) e.target.classList.add('visible');
    });
  }, { threshold: 0.12, rootMargin: '0px 0px -40px 0px' });
  els.forEach(el => obs.observe(el));
})();

/* ══════════════════════════════════════════
   7. DARK COUNTER ANIMATION
══════════════════════════════════════════ */
(function initDarkCounters() {
  const nums = document.querySelectorAll('.dc-num[data-target]');
  if (!nums.length) return;
  let done = false;
  const obs = new IntersectionObserver(entries => {
    if (entries[0].isIntersecting && !done) {
      done = true;
      nums.forEach(el => {
        const target = parseInt(el.dataset.target, 10);
        let cur  = 0;
        const step = Math.max(1, Math.ceil(target / 55));
        const t = setInterval(() => {
          cur += step;
          if (cur >= target) {
            el.textContent = target + (target >= 12 ? '+' : '');
            clearInterval(t);
          } else {
            el.textContent = cur;
          }
        }, 26);
      });
    }
  }, { threshold: 0.3 });
  const strip = document.querySelector('.dark-counters');
  if (strip) obs.observe(strip);
})();

/* ══════════════════════════════════════════
   8. 3D CARD TILT
══════════════════════════════════════════ */
(function initCardTilt() {
  const wrapper = document.getElementById('pcCardWrapper');
  const card    = document.getElementById('pcCard');
  if (!wrapper || !card) return;
  wrapper.addEventListener('mousemove', e => {
    const r  = wrapper.getBoundingClientRect();
    const nx = (e.clientX - r.left) / r.width  - 0.5;
    const ny = (e.clientY - r.top)  / r.height - 0.5;
    card.style.transition = 'box-shadow .15s';
    card.style.transform  = `rotateX(${ny * -16}deg) rotateY(${nx * 20}deg) scale3d(1.025,1.025,1.025)`;
    card.style.boxShadow  =
      `${-nx * 28}px ${-ny * 28}px 60px rgba(139,92,246,0.28),
       ${-nx * 12}px ${-ny * 12}px 30px rgba(0,245,212,0.12),
       0 20px 60px rgba(0,0,0,0.5)`;
  });
  wrapper.addEventListener('mouseleave', () => {
    card.style.transition = 'transform .6s cubic-bezier(0.16,1,0.3,1), box-shadow .4s';
    card.style.transform  = 'rotateX(0deg) rotateY(0deg) scale3d(1,1,1)';
    card.style.boxShadow  =
      '0 0 0 1px rgba(0,245,212,0.07), 0 20px 60px rgba(0,0,0,0.5), 0 0 80px rgba(0,245,212,0.10)';
  });
})();
